import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart, ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PriorityMessage {
  subject: string;
  sender: string;
  received: string;
}

interface DailyVolume {
  day: string;
  emails: number;
}

interface EmailWidgetData {
  unreadCount: number;
  priorityMessages: PriorityMessage[];
  dailyVolumeTrend: DailyVolume[];
}

export default function Widget() {
  const data = response.data as EmailWidgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F8FAFC', mb: 1 }}>
              Email Inbox
            </Typography>
            <Typography variant="body1" sx={{ color: '#94A3B8' }}>
              Unread Emails: <strong>{data.unreadCount}</strong>
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 1 }}>
              Priority Messages
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {data.priorityMessages.map((message, index) => (
                <Chip
                  key={index}
                  label={message.subject}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, color: '#F8FAFC', bgcolor: '#334155' }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: data.dailyVolumeTrend.map(d => d.emails),
                  color: '#3B82F6',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.dailyVolumeTrend.map(d => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'emails' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="emails"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
